mapper.select:
SELECT R.등록번호 resumeRegNo, R.구직번호 resumeJobNo, P.참여자 participantName, P.지점 branch, P.전담자_계정 counselorAccount, M.이름 counselorName, R.기업명 companyName, R.담당자명 managerName, R.이메일 managerEmail, R.비상연락처 emergencyContact, R.상태 requestStatus, CONVERT(varchar, R.등록일, 120) resumeRegDate, CONVERT(varchar, R.수정일, 120) resumeUpdateDate FROM J_참여자관리_이력서요청양식 R LEFT JOIN J_참여자관리 P ON R.구직번호 = P.구직번호 LEFT JOIN J_참여자관리_로그인정보 M ON P.전담자_계정 = M.아이디 WHERE 1=1
AND P.지점 = #{searchBranch}
AND P.전담자_계정 = #{searchCounselor}
AND P.참여자 LIKE '%' + #{searchName} + '%'
AND R.상태 = #{searchStatus}
AND R.등록일 >= CAST(#{searchStartDate} AS date)
AND R.등록일 < DATEADD(day, 1, CAST(#{searchEndDate} AS date))
ORDER BY R.등록번호 DESC
